def anahtar kelimesiyle tanimlarsin:
def selamla():
    print("Merhaba!")
selamla()

return ile sonucu dondurursun:
def topla(a, b):
    return a + b
print(topla(4, 6))

def ile tanimlayip cagirirsin:
def merhaba(isim):
    print("Selam", isim)
merhaba("Mehmet")

return ile farki dondurursun:
def fark(a, b):
    return a - b
print(fark(10, 3))

Dikdörtgen çevresi fonksiyonu:

def dikdortgen_cevre(en, boy):
    return 2 * (en + boy)

print(dikdortgen_cevre(5, 3))  # 16

Recursive (öz yinelemeli) faktöriyel:

def faktoriyel(n):
    return 1 if n <= 1 else n * faktoriyel(n - 1)

print(faktoriyel(4))  # 24

Listenin ortalamasını veren fonksiyon:

def ortalama(liste):
    return sum(liste) / len(liste)

print(ortalama([2, 4, 6]))  # 4.0

Ortalama fonksiyonu:

def ortalama(sayilar):
    return sum(sayilar) / len(sayilar)

print(ortalama([10, 20, 30, 40]))  # 25.0

En büyük sayıyı bulan fonksiyon:

def en_buyuk(liste):
    return max(liste)

print(en_buyuk([3, 9, 1, 7]))  # 9

En küçük sayıyı bulan fonksiyon:

def en_kucuk(liste):
    return min(liste)

print(en_kucuk([3, 9, 1, 7]))  # 1

Üç sayının en büyüğü için:

def en_buyuk3(a, b, c):
    return max(a, b, c)

print(en_buyuk3(4, 9, 6))  # 9

Listedeki toplam için:

def liste_topla(liste):
    return sum(liste)

print(liste_topla([5, 10, 15]))  # 30

Mutlak farkı veren fonksiyon:

def mutlak_fark(a, b):
    return abs(a - b)

print(mutlak_fark(3, 8))  # 5

Min ve max'ı birlikte veren fonksiyon:

def min_max(liste):
    return min(liste), max(liste)

print(min_max([5, 2, 9, 1]))  # (1, 9)

for dongusu ile 1'den 10'a kadar yazdirabilirsin:
for i in range(1, 11):
    print(i)

range kullanarak kolayca yapilir:
for i in range(1, 11):
    print(i)

range(10) dogrudan 0..9 verir:
for i in range(10):
    print(i)

sum ile kisa bir fonksiyon yeterli:
def topla(n):
    return sum(range(1, n + 1))
print(topla(10))

Mod (%) ile kontrol edilir:
sayi = 7
if sayi % 2 == 0:
    print("Cift")
else:
    print("Tek")

range adimini 2 yaparak ciftleri alirsin:
for i in range(2, 21, 2):
    print(i)

1'den baslayip 2'ser artarak tekleri yazdirirsin:
for i in range(1, 21, 2):
    print(i)

range'i negatif adimla geriye saydirabilirsin:
for i in range(5, 0, -1):
    print(i)

if/elif/else ile uc durumu ayirabilirsin:
sayi = -3
if sayi > 0:
    print("Pozitif")
elif sayi < 0:
    print("Negatif")
else:
    print("Sifir")

if/else ile karsilastirabilirsin:
a, b = 5, 9
if a > b:
    print(a)
else:
    print(b)

Basit bir if/else yeterli:
not_ = 65
if not_ >= 50:
    print("Gecti")
else:
    print("Kaldi")

Dongu icinde mod ile kontrol edersin:
for i in range(1, 51):
    if i % 3 == 0:
        print(i)

range adimini 5 vererek dogrudan yazdirabilirsin:
for i in range(5, 51, 5):
    print(i)

Dongu ve mod kontroluyle ciftleri secersin:
liste = [1, 2, 3, 4, 5, 6]
for sayi in liste:
    if sayi % 2 == 0:
        print(sayi)

Dongu icinde i*i hesaplarsin:
for i in range(1, 11):
    print(i * i)

in operatoru uyelik kontrolu yapar:
liste = [1, 2, 3]
if 2 in liste:
    print("Var")
else:
    print("Yok")

Mod kontroluyle tekleri sayabilirsin:
adet = 0
for i in range(1, 31):
    if i % 2 == 1:
        adet += 1
print(adet)

and ile iki kosulu birlikte kontrol edersin:
sayi = 15
if sayi % 3 == 0 and sayi % 5 == 0:
    print("Her ikisine de bolunur")
else:
    print("Bolunmez")

range'i 10'dan 1'e negatif adimla calistirirsin:
for i in range(10, 0, -1):
    print(i)

Python'da zincirli karsilastirma kullanilir:
sayi = 42
if 0 <= sayi <= 100:
    print("Aralikta")
else:
    print("Aralik disinda")

continue ile istedigin degeri atlayabilirsin:
for i in range(1, 16):
    if i == 7:
        continue
    print(i)

break ile donguyu erken sonlandirirsin:
for i in range(1, 100):
    if i == 5:
        break
    print(i)

for dongusu ile her elemani gezersin:
liste = ["a", "b", "c"]
for eleman in liste:
    print(eleman)

for dongusu kullanabilirsin:
sayilar = [1, 2, 3]
for s in sayilar:
    print(s)

for dongusu ile her harfi gezersin:
kelime = "kus"
for harf in kelime:
    print(harf)
